<div class="d-flex justify-content-between align-items-end mb-4"><div><h1 class="h3">Job cost analysis</h1><p class="text-muted mb-0">Revenue less labor, materials, and vehicle allocation.</p></div><form class="d-flex gap-2"><input class="form-control" type="date" name="from" value="<?=e($from)?>"><input class="form-control" type="date" name="to" value="<?=e($to)?>"><button class="btn btn-primary">Apply</button></form></div><div class="card"><div class="card-body"><div class="table-responsive"><table class="table"><thead><tr><th>Job</th><th>Customer</th><th>Revenue</th><th>Labor</th><th>Materials</th><th>Vehicle</th><th>Gross profit</th><th>Margin</th></tr></thead><tbody><?php foreach($rows as $r):$margin=(float)$r['revenue']>0?((float)$r['gross_profit']/(float)$r['revenue']*100):0;?><tr><td><?=e($r['job_number'])?><small class="d-block text-muted"><?=e($r['service_summary'])?></small></td><td><?=e($r['customer'])?></td><td><?=money($r['revenue'])?></td><td><?=money($r['labor_cost'])?></td><td><?=money($r['material_cost'])?></td><td><?=money($r['vehicle_cost'])?></td><td class="fw-bold"><?=money($r['gross_profit'])?></td><td><?=number_format($margin,1)?>%</td></tr><?php endforeach?></tbody></table></div></div></div>
